// ========================================================================
// BF16 recurrence (prefill, fixed-length)
// ========================================================================

extern "C" void gdn_recurrence_bf16(
    const __bf16* q, const __bf16* k, const __bf16* v,
    const float* g, const float* beta, float* state, float* out,
    int bh, int seq_len, int k_dim, int v_dim,
    unsigned int num_blocks, unsigned int dim_blocks, void* stream_) {
    gdn_recurrence_bf16_wrapper(
        (void*)q, (void*)k, (void*)v,
        (float*)g, (float*)beta, state, out,
        bh, seq_len, k_dim, v_dim, stream_);
}

// ========================================================================
// BF16 decode slots (batched, slot-aware)
// ========================================================================

extern "C" void gdn_decode_slots_bf16(
    const __bf16* q, const __bf16* k, const __bf16* v,
    const float* g, const float* beta,
    float* state, const int64_t* slots_i64, float* out,
    int batch, int heads, int k_dim, int v_dim,
    int max_slots,
    unsigned int num_blocks, unsigned int dim_blocks, void* stream_) {
    gdn_decode_slots_bf16_wrapper(
        (void*)q, (void*)k, (void*)v,
        (float*)g, (float*)beta,
        state, (int64_t*)slots_i64, out,
        batch, heads, k_dim, v_dim, max_slots,
        stream_);
}

// ========================================================================
// BF16 varlen recurrence (prefill, variable-length with slot DMA)
// ========================================================================

extern "C" void gdn_recurrence_varlen_bf16(
    const __bf16* q, const __bf16* k, const __bf16* v,
    const __bf16* g, const __bf16* beta,
    float* state, const int64_t* slots_i64,
    __bf16* out, const uint32_t* cu_seqlens,
    int total_tokens, int batch, int num_heads, int k_dim, int v_dim,
    int max_slots,
    unsigned int num_blocks, unsigned int dim_blocks, void* stream_) {
    if (total_tokens == 0) return;
    gdn_recurrence_varlen_bf16_wrapper(
        (void*)q, (void*)k, (void*)v,
        (void*)g, (void*)beta,
        state, (int64_t*)slots_i64, (void*)out, (uint32_t*)cu_seqlens,
        total_tokens, batch, num_heads, num_heads,
        max_slots, k_dim, v_dim, stream_);
}

