// ========================================================================
// BF16 fused gating
// ========================================================================

extern "C" void gdn_fused_gating_bf16(
    const float* a_log, const __bf16* a, const __bf16* b, const float* dt_bias,
    __bf16* g, __bf16* beta,
    int total, int num_heads, void* stream) {
    if (total == 0) return;
    gdn_fused_gating_bf16_wrapper(
        (void*)a_log, (void*)a, (void*)b, (void*)dt_bias,
        (void*)g, (void*)beta,
        total, num_heads, stream);
}

