// BF16 L2 normalization
// ========================================================================

extern "C" void gdn_l2_norm_bf16(
    const __bf16* input, __bf16* output,
    int rows, int dim, void* stream) {
    if (rows == 0) return;
    gdn_l2_norm_bf16_wrapper(
        (void*)input, (void*)output,
        rows, dim, stream);
}

// ========================================================================
// BF16 gated RMSNorm + SiLU
// ========================================================================

extern "C" void gdn_gated_rmsnorm_bf16(
    const __bf16* x, const __bf16* z, const float* gamma,
    __bf16* out, int rows, int dim, void* stream) {
    if (rows == 0) return;
    gdn_gated_rmsnorm_bf16_wrapper(
        (void*)x, (void*)z, (void*)gamma, (void*)out,
        rows, dim, stream);
}

// ========================================================================
// BF16 causal conv1d (unified prefill + decode)
// ========================================================================

static __bf16* s_prod_zero_bias = nullptr;
static int s_prod_zero_bias_dim = 0;

static __bf16* ensure_zero_bias(int d_conv) {
    if (s_prod_zero_bias && s_prod_zero_bias_dim >= d_conv) return s_prod_zero_bias;
    if (s_prod_zero_bias) topsFree(s_prod_zero_bias);
    topsMalloc((void**)&s_prod_zero_bias, d_conv * sizeof(__bf16));
    topsMemset(s_prod_zero_bias, 0, d_conv * sizeof(__bf16));
    s_prod_zero_bias_dim = d_conv;
    return s_prod_zero_bias;
}

extern "C" void causal_conv1d_fwd_choreo_bf16(
    const __bf16* x, const __bf16* weight, const __bf16* bias,
    __bf16* conv_state, const int64_t* cache_idx, const uint32_t* qsl,
    __bf16* out,
    int total_tokens, int d_conv, int batch, int kernel_size,
    int silu_activation, int max_slots, void* stream_) {
    const __bf16* bias_ptr = bias ? bias : ensure_zero_bias(d_conv);
    causal_conv1d_fwd_bf16_prod_wrapper(
        (void*)x, (void*)weight, (void*)bias_ptr, (void*)conv_state,
        (int64_t*)cache_idx, (uint32_t*)qsl, (void*)out,
        (silu_activation != 0),
        total_tokens, d_conv, batch, kernel_size, max_slots, stream_);
}

